
local 怪物属性 = class()
local jhf = string.format
local random = math.random
local qz=math.floor
local sj = 取随机数
local sjlx={"物理","法系","物法"}
local 战斗单位={}
local sx

function 取人物修炼等级上限(等级)
  local 修炼上限=(等级-20)/5
  if 修炼上限<=0 then
      修炼上限=0
  end
  if 修炼上限>=25 then
    修炼上限=25
  end
  return 修炼上限
end

function 取难度怪修炼上限(等级)
  local 修炼上限=(等级-20)/5
  if 修炼上限<=0 then
      修炼上限=0
  end
  if 修炼上限>=30 then
    修炼上限=30
  end
  return 修炼上限
end

function 怪物属性:置怪物难度配置(data)
	if data and type(data) == "table" and data[1] then
		for sx,v in pairs(Q_怪物难度配置) do
			for n=1,#data do
				if data[n][sx] then
					data[n][sx] = math.floor(data[n][sx] * v)
				end
			end
		end
		return data
	end
	return data
end

function 怪物属性:热更怪物属性函数()
    local wenjj = self:规范化路径(程序目录 .. "怪物参数")
    if not f函数 or not f函数.文件是否存在(wenjj) then
        print("错误：怪物参数目录不存在 - " .. wenjj)
        return false
    end

    local data = self:获取无后缀文件名列表(wenjj)
    local 成功计数 = 0
    local 失败计数 = 0

    -- 增加文件状态缓存，避免重复加载未修改的文件
    self.文件状态缓存 = self.文件状态缓存 or {}

    for _, xxx in ipairs(data) do
        -- 检查文件是否需要更新
        if self:检查文件是否需要更新(xxx, wenjj) then
            if not self:执行热更(xxx) then
                print("热更新失败:", xxx)
                失败计数 = 失败计数 + 1
            else
                成功计数 = 成功计数 + 1
                -- 记录文件状态
                self:记录文件状态(xxx, wenjj)
            end
        end
    end

    -- 加载数据（如果有成功更新）
    if 成功计数 > 0 then
        self:加载数据()
    end

    -- 只打印统计信息
    if #data > 0 then
        print(string.format("怪物参数热更新：读取 %d 个文件，成功 %d 个，失败 %d 个", #data, 成功计数, 失败计数))
    end

    return 成功计数 > 0 or 失败计数 == 0
end

function 怪物属性:读入文本(文件名)
    -- 参数校验
    if type(文件名) ~= "string" or 文件名:match("%.%.") then
        print("[安全错误] 非法文件名:", 文件名)
        return nil
    end

    -- 构建完整路径（自动处理跨平台路径）
    local 基础路径 = self:规范化路径(程序目录 .. "怪物参数/")
    local 文件路径 = self:规范化路径(基础路径 .. "/"..文件名)

    -- 检查基础目录是否存在
    if not f函数 or not f函数.文件是否存在(基础路径) then
        print("[错误] 基础目录不存在:", 基础路径)
        return nil
    end

    -- 双重文件存在检查
    local 文件实际存在 = false
    if f函数.文件是否存在(文件路径) then
        文件实际存在 = true
    else
        -- 备用检查方式
        local 测试文件 = io.open(文件路径, "r")
        if 测试文件 then
            文件实际存在 = true
            测试文件:close()
        end
    end

    if not 文件实际存在 then
        -- 只保留错误信息，不打印调试信息
        print("[错误] 文件不存在:", 文件路径)
        return nil
    end

    -- 检查文件类型（防止读取非文本文件）
    if not 文件名:match("%.txt$") then
        print("[安全错误] 仅支持.txt文件:", 文件名)
        return nil
    end

    -- 读取文件内容（带错误处理）
    local 文件内容
    local 文件句柄, 错误信息 = io.open(文件路径, "rb")

    if not 文件句柄 then
        print("[IO错误] 无法打开文件:", 错误信息)
        return nil
    end

    -- 增加文件大小限制（防止读取超大文件）
    local 最大文件大小 = 1024 * 1024  -- 1MB
    local 文件大小 = 文件句柄:seek("end")
    文件句柄:seek("set")

    if 文件大小 > 最大文件大小 then
        print("[错误] 文件超过大小限制:", 文件大小)
        文件句柄:close()
        return nil
    end

    文件内容 = 文件句柄:read("*a")
    文件句柄:close()

    -- 处理UTF-8 BOM头
    if 文件内容:sub(1,3) == "\239\187\191" then
        文件内容 = 文件内容:sub(4)
    end

    -- 检查内容有效性
    if not 文件内容 or 文件内容:match("^%s*$") then
        print("[警告] 文件内容为空:", 文件路径)
        return nil
    end

    return 文件内容
end

function 怪物属性:获取无后缀文件名列表(文件夹路径)
    local 文件列表 = {}
    文件夹路径 = self:规范化路径(文件夹路径)

    -- 添加目录存在检查
    if not f函数.文件是否存在(文件夹路径) then
        print("[错误] 目录不存在:", 文件夹路径)
        return 文件列表
    end

    for 文件名 in lfs.dir(文件夹路径) do
        if 文件名 ~= "." and 文件名 ~= ".." then
            -- 去除文件名中的空格
            文件名 = 文件名:gsub("%s+", "")
            local 无后缀名 = 文件名:match("^(.*)%.txt$")
            if 无后缀名 then
                -- 去除无后缀名中的空格
                无后缀名 = 无后缀名:gsub("%s+", "")
                table.insert(文件列表, 无后缀名)
            end
        end
    end

    -- 排序文件名，确保加载顺序一致
    table.sort(文件列表)

    return 文件列表
end

function 怪物属性:执行热更(_text)
    -- 安全检查
    if _text:match("%.%.") then
        print("安全错误：非法文件名 - " .. _text)
        return false
    end

    -- 去除文本中的空格
    _text = _text:gsub("%s+", "")

    local 文件名 = _text .. ".txt"
    local str = self:读入文本(文件名)
    if not str then
        print("无法读取文件:", 文件名)
        return false
    end

    -- 创建执行环境
    local env = {
        -- 核心对象
        Q_函数 = self,
        self = self,

        -- 允许访问所有全局变量
        _G = _G,

        -- 将局部变量也放入环境
        sj = sj,  -- 这里引用的是当前作用域的局部变量sj，即您之前定义的取随机数
        jhf = jhf,
        random = random,
        qz = qz,
        sjlx = sjlx,
        战斗单位 = 战斗单位,
        sx = sx,
        取人物修炼等级上限 = 取人物修炼等级上限,  -- 注意：这个函数是全局函数吗？如果是，因为复制了_G，所以可以不用单独加，但为了明确也可以加上
    }

    -- 将_G中的所有内容复制到env中（这样脚本可以直接访问全局变量）
    for k, v in pairs(_G) do
        env[k] = v
    end

    -- 加载并执行脚本
    local 代码函数, 错误信息 = load("return function(Q_函数)\n"..str.."\nend", 文件名.."[热更新]", "t", env)
    if not 代码函数 then
        print("脚本加载错误:", 错误信息)
        return false
    end

    local 成功, 错误 = pcall(代码函数(), self)
    if not 成功 then
        print("脚本执行错误:", 错误)
        return false
    end

    return true
end
-- 新增：检查文件是否需要更新
function 怪物属性:检查文件是否需要更新(文件名, 目录路径)
    -- 如果还没有缓存，认为需要更新
    if not self.文件状态缓存 then
        return true
    end

    local 文件路径 = self:规范化路径(目录路径 .. "/" .. 文件名 .. ".txt")
    local 文件属性 = lfs.attributes(文件路径)

    if not 文件属性 then
        return true  -- 文件不存在，但被列出？可能有问题，但返回true触发重新检查
    end

    local 缓存 = self.文件状态缓存[文件名]

    -- 如果没有缓存，或者文件被修改了，需要更新
    if not 缓存 or 缓存.修改时间 ~= 文件属性.modification then
        return true
    end

    return false
end

-- 新增：记录文件状态
function 怪物属性:记录文件状态(文件名, 目录路径)
    self.文件状态缓存 = self.文件状态缓存 or {}

    local 文件路径 = self:规范化路径(目录路径 .. "/" .. 文件名 .. ".txt")
    local 文件属性 = lfs.attributes(文件路径)

    if 文件属性 then
        self.文件状态缓存[文件名] = {
            修改时间 = 文件属性.modification,
            大小 = 文件属性.size,
            记录时间 = os.time()
        }
    end
end

-- 新增：清理文件状态缓存
function 怪物属性:清理文件状态缓存()
    self.文件状态缓存 = {}
    print("已清理文件状态缓存")
end

-- 规范化路径（保持不变）
function 怪物属性:规范化路径(path)
    -- 统一使用正斜杠并去除多余斜杠
    path = path:gsub("\\", "/"):gsub("/+", "/")
    -- 移除末尾的斜杠(除非是根目录)
    if path ~= "/" then
        path = path:gsub("/$", "")
    end
    return path
end

