function 取招式特效(mp)
	local lssj = {
	  	大唐官府 = {"横扫千军"},
	  	化生寺 = {"唧唧歪歪","金刚护法","推气过宫","金刚护体"},
	  	女儿村 = {"似玉生香"},
	  	方寸山 = {"失心符","五雷咒"},
	  	天宫 = {"天雷斩","雷霆万钧"},
	  	普陀山 = {"普渡众生"},
	  	龙宫 = {"龙卷雨击"},
	  	五庄观 = {"日月乾坤"},
	  	狮驼岭 = {"鹰击"},
	  	魔王寨 = {"飞砂走石","三昧真火","牛劲","风云变色"},
	  	阴曹地府 = {"阎罗令"},
	  	盘丝洞 = {"含情脉脉"},
	  	神木林 = {"落叶萧萧"},
	  	凌波城 = {"翻江搅海"},
	  	无底洞 = {"地涌金莲"},
		花果山 = {nil},
	}
 	local fhsj = {}
 	if lssj[mp] ~= nil then
	  	for i=1,#lssj[mp] do
			fhsj[lssj[mp][i]] = true
	  	end
 	end
