function 怪物属性:取沸涌炎海的信标信息(任务id,玩家id,序号)---沸涌炎海的信标
	local 战斗单位={}
	local 等级=取队伍最高等级数(玩家数据[玩家id].队伍,玩家id)
	local xlz = qz(1+等级/50)*10 --怪修炼
	local qmenpai = {"狮驼岭","大唐官府","大唐官府","狮驼岭","龙宫","神木林","魔王寨","普陀山","五庄观","化生寺","凌波城","阴曹地府"}
	local 随机阵法 = {"天覆阵","地载阵","风扬阵","云垂阵","龙飞阵","虎翼阵","鸟翔阵","蛇蟠阵","鹰啸阵"}
	local q门派 = qmenpai[i]
	local sx = self:取属性(等级,self:取随机输出门派())
	战斗单位[1]={
	名称="八极∷姑苏城"
	,模型="自在天魔"
	,附加阵法=随机阵法[取随机数(1,#随机阵法)]
		    ,等级=等级+15
		    ,递增伤害=true
		    ,物伤减少=0.6
	                ,法伤减少=0.6
		    ,法宝={[1]={名称="金甲仙衣",境界=9},[2]={名称="降魔斗篷",境界=12}}
		    ,气血 = qz(1+等级/50)*12000+150000
		    ,伤害 = qz(1+等级/50)*400+1500+1400
		    ,法伤 = qz(1+等级/500)*350+1400+600
		    ,防御 = qz(1+等级/100)*300+1000+300
		    ,法防 = qz(1+等级/100)*200+900+200
		    ,速度 = qz(1+等级/100)*200+600
		    ,固定伤害 = qz(1+等级/100)*350
		    ,治疗能力 = 等级*20+20000
		    ,封印命中等级=等级+100
