function 怪物属性:精锐六九(任务id,玩家id,序号)---精锐组挑战
local 战斗单位={}
	 local 锦衣={"青花瓷","浮生","浮生绡·点黛","小福兔·月白","春日宴","旃檀香·墨黑","灼灼韶华","青花瓷月白","青花瓷月黑","齐天大圣月白"}
	 local qzf = Q_阵法名[取随机数(1,#Q_阵法名)]
	 --local 主模型=任务数据[任务id].模型
	 --local 名称=任务数据[任务id].名称
	 local 等级=69
	 local 难度系数=1.2

	 for i=1,3 do
	 local 人物=Qu随机角色[取随机数(1,#Qu随机角色)]
	 local 门派=Qu角色属性[人物].门派[取随机数(1,#Qu角色属性[人物].门派)]
	 sx = self:取属性(等级,门派)
	 local 名称范围 = {"执我之手","白衣煮茶","黑白棋局","忘不了她","半夏白色枕头","末世岛屿","携我之心","哼哈二将","对面是二傻","繁华宛似浮云","風卷著沙","纪年海泊","沉鱼落雁","Louise"}
	 local 武器属性=取120角色武器(人物)

	 战斗单位[i]={
		  名称=名称范围[取随机数(1,#名称范围)]
		  ,模型=人物
		  ,等级=等级
		  ,角色=true
		  ,附加阵法=qzf
