	 	,法伤 = qz(1+难度/10+等级/100)*500+2200
	 	,防御 = qz(1+难度/10+等级/100)*500+500
	 	,法防 = qz(1+难度/10+等级/100)*500+100
	 	,速度 = qz(1+难度/10+等级/100)*200+500
	 	,固定伤害 = qz(1+难度/10+等级/100)*600+1500
	 	,治疗能力 = 等级*125+25000
	 	,封印命中等级=等级+100
	 	,抵抗封印等级=等级+100
	 	,修炼 = {物抗=xlz,法抗=xlz,攻修=xlz}
	 	,技能={"高级感知","高级夜战","高级吸血","高级幸运","高级神佑复生","高级偷袭","高级魔之心","高级法术暴击","反震"}
	 	,门派=sx.门派
	 	,AI战斗 = {AI=sx.智能}
	 }
	 	end
	 	local 物伤减少随机怪 = 取随机数(1,10)
	 	local 法伤减少随机怪 = 物伤减少随机怪 + 1
	 	if 法伤减少随机怪 >= 11 then
	 		法伤减少随机怪 = 1
	 	end
		战斗单位[物伤减少随机怪].物伤减少 = 0.7--0.001
		战斗单位[法伤减少随机怪].法伤减少 = 0.7--0.001
		return 战斗单位
	end

