		   ,主动技能=取随机功法组合(15)
	 }
	 end
	 local 物伤减少随机怪 = 取随机数(1,16)
	local 法伤减少随机怪 = 物伤减少随机怪 + 1
	if 法伤减少随机怪 >= 17 then
		法伤减少随机怪 = 1
	end
	战斗单位[物伤减少随机怪].物伤减少 = 0.7--0.001
	战斗单位[法伤减少随机怪].法伤减少 = 0.7--0.001
	 return 战斗单位
end
