	local 玩家境界 = 时空之钥[玩家id].境界
	local 基础难度 = 1.5
	local 难度增加量 = 0.1
	local 难度 = 基础难度 + (玩家境界 - 1) * 难度增加量
	if 玩家境界 == 1 then
	    难度 = 基础难度
	end
	local 等级=取队伍最高等级数(玩家数据[玩家id].队伍,玩家id)
	local sx =    self:取属性(等级,"无底洞","固伤")
	 战斗单位[1]={
		  名称="地涌夫人"
		  ,模型="地涌夫人"
		  ,等级=等级
		  ,气血 = 等级 * 等级*4*难度* QAQ[序号].抗封等级[1]
		  ,伤害 = 等级 * 14*难度* QAQ[序号].伤害系数[1]
		  ,法伤 = 等级 * 8*难度* QAQ[序号].法伤系数[1]
		  ,速度 = 等级 * 3.5*难度* QAQ[序号].速度系数[1]
		  ,防御 = 等级 * 10*难度* QAQ[序号].防御系数[1]
		  ,法防 = 等级 * 8*难度* QAQ[序号].法防系数[1]
		  ,固定伤害 = qz(等级*2)
		  ,治疗能力 = qz(等级*2)
		  ,技能={"感知"}
		  ,门派=sx.门派
		  ,AI战斗 = {AI=sx.智能}
	 }
    sx = self:取属性(等级,"神木林")
    for i=2,5 do
	 战斗单位[i]={
		  名称="炽热地纹"
		  ,模型="巨石守卫夜"
		  ,等级=等级
		  ,染色方案=66
          ,染色组={[1]=1,[2]=0}
		  ,气血 = 等级 * 等级*1.5*难度* QAQ[序号].抗封等级[1]
		  ,伤害 = 等级 * 10*难度* QAQ[序号].抗封等级[1]
		  ,法伤 = 等级 * 8*难度* QAQ[序号].法伤系数[1]
		  ,速度 = 等级 * 2*难度* QAQ[序号].抗封等级[1]
		  ,防御 = 等级 * 10*难度* QAQ[序号].防御系数[1]
		  ,法防 = 等级 * 8*难度* QAQ[序号].法防系数[1]
		  ,固定伤害 = qz(等级*2)
		  ,治疗能力 = qz(等级*2)
		  ,技能={"感知"}
		  ,门派=sx.门派
		  ,AI战斗 = {AI=sx.智能}
	 }
    end
    for i=6,8 do
	 战斗单位[i]={
		  名称="隙中岩浆"
		  ,模型="蜃气妖"
		  ,等级=等级
		  ,染色方案=62
          ,染色组={[1]=1,[2]=0}
		  ,气血 = 等级 * 等级*1.5*难度* QAQ[序号].抗封等级[1]
		  ,伤害 = 等级 * 10*难度* QAQ[序号].抗封等级[1]
		  ,法伤 = 等级 * 8*难度* QAQ[序号].法伤系数[1]
		  ,速度 = 等级 * 2*难度* QAQ[序号].抗封等级[1]
		  ,防御 = 等级 * 10*难度* QAQ[序号].防御系数[1]
		  ,法防 = 等级 * 8*难度* QAQ[序号].法防系数[1]
		  ,固定伤害 = qz(等级*2)
		  ,治疗能力 = qz(等级*2)
		  ,技能={"感知"}
		  ,技能={"烈火","地狱烈火"}
	 }
    end
	 return 战斗单位
end
