function 怪物属性:取剑会天下BB技能(属性,技能)
  local 最高属性 = {"力量",0}
  --结算出最高宠物属性
  --BB身上可以添加 主动技能 和 技能
  for n,v in pairs(属性) do
    if v>最高属性[2] then
      最高属性[1]=n
      最高属性[2]=v
    end
  end

  --如果最高属性与力量相等则为力量
  if 最高属性[2]== 属性["力量"] then
    最高属性[1]="力量"
  end
  --判断最高属性决定BB技能
  if 最高属性[1] == "力量" then
    local 高级技能 = {"从天而降","嗜血追击","须弥真言","灵能激发","高级反震","高级吸血","高级反击","高级连击","高级飞行","高级夜战","高级隐身","高级感知","高级再生","高级冥思","高级慧根","高级必杀","高级幸运","高级神迹","高级招架","高级永恒","高级敏捷","高级夜战","高级再生","高级防御","高级偷袭","高级毒","高级驱鬼","高级鬼魂术","高级魔之心","高级神佑复生","高级精神集中","高级否定信仰","高级法术连击","高级法术暴击","高级法术波动","高级雷属性吸收","高级土属性吸收","高级火属性吸收","高级水属性吸收"}
    local 主动技能 = {"壁垒击破","法术防御","奔雷咒","泰山压顶","水漫金山","地狱烈火","八凶法阵","月光","天降灵葫","上古灵符","叱咤风云","力劈华山","剑荡四方","死亡召唤","善恶有报","壁垒击破","惊心一剑"}
    local 数量 = 0
    local 返回 = {技能={},主动技能={}}
    for n=1,#技能 do
      for i=1,#高级技能 do
        if 技能[n] == 高级技能[i] then
          数量 = 数量 + 1
          返回.技能[#返回.技能+1] = 技能[n]
          table.remove(高级技能,i)
          break
        end
      end
    end
    if #技能 - 数量 > 0 then
      for n=1,#技能 - 数量 do
        local jns = 取随机数(1,#高级技能)
        返回.技能[#返回.技能+1] = 高级技能[jns]
        table.remove(高级技能,jns)
      end
    end
    返回.主动技能 = {主动技能[取随机数(1,#主动技能)]}
    return 返回
  elseif 最高属性[1] == "魔力" then
    local 高级技能 = {"从天而降","嗜血追击","须弥真言","灵能激发","高级反震","高级吸血","高级反击","高级连击","高级飞行","高级夜战","高级隐身","高级感知","高级再生","高级冥思","高级慧根","高级必杀","高级幸运","高级神迹","高级招架","高级永恒","高级敏捷","高级夜战","高级再生","高级防御","高级偷袭","高级毒","高级驱鬼","高级鬼魂术","高级魔之心","高级神佑复生","高级精神集中","高级否定信仰","高级法术连击","高级法术暴击","高级法术波动","高级雷属性吸收","高级土属性吸收","高级火属性吸收","高级水属性吸收"}
    local 主动技能 = {"壁垒击破","法术防御","奔雷咒","泰山压顶","水漫金山","地狱烈火","八凶法阵","月光","天降灵葫","上古灵符","叱咤风云","力劈华山","剑荡四方","死亡召唤","善恶有报","壁垒击破","惊心一剑"}
    local 数量 = 0
    local 返回 = {技能={},主动技能={}}
    for n=1,#技能 do
      for i=1,#高级技能 do
        if 技能[n] == 高级技能[i] then
          数量 = 数量 + 1
