function 怪物属性:取比武属性(lv,门派,类型) --固伤 辅助 物理 法系
	 --如果没写 门派 返回的是随机技能  没类型返回随机类型
	 local 技能={}
	 if 门派==nil then
		  if 类型==nil then
				类型=sjlx[取随机数(1,#sjlx)]
		  end
		  if 类型=="物理" then
				技能=取随机物攻(3)
		  elseif 类型=="法系" then
				技能=取随机法攻(3)
		  elseif 类型=="物法" then
				技能=取随机功法组合(3)
		  end
		  return {属性=self:比武属性表(lv,类型),技能组=技能}
	 else
		  if 类型==nil then
				类型=self.数据[门派][取随机数(1,#self.数据[门派])]
		  end
		  return {属性=self:比武属性表(lv,类型),智能=类型,门派=门派}
	 end
end

