function 怪物属性:巡山小妖(任务id,玩家id,序号)
	 local 战斗单位={}
	 local 等级=取队伍最高等级数(玩家数据[玩家id].队伍,玩家id)
	 local 模型范围={"蛤蟆精","蜘蛛精","老虎","雷鸟人","大蝙蝠","野猪","雷鸟人","骷髅怪","小龙女","虾兵","蟹将","鬼蛙","龟丞相","金乌火虫","黑熊","黑熊精"}
	 local 难度=  1
	 local sx = self:取属性(等级)
	 战斗单位[1]={
		  名称=任务数据[任务id].名称
		  ,模型=任务数据[任务id].模型
		  ,等级=等级
		  ,饰品显示=true
		  ,气血 = qz((sx.属性.气血+等级*150)*难度)+等级*123.2
	 	  ,伤害 = qz(sx.属性.伤害*难度)+222.7
	 	  ,法伤 = qz(sx.属性.法防*难度)+111.9
		  ,速度 = qz(sx.属性.速度*难度)
		  ,固定伤害 = qz(等级*2*难度)
		  ,治疗能力 = qz(等级*2*难度)
		  ,防御 = 13.13+等级*6
		  ,法防 = 12.12+等级*0
		  --,修炼 = {物抗=qz((等级-20)/12),法抗=qz((等级-20)/12),攻修=qz((等级-20)/12)}
		  ,门派=sx.门派
		  ,AI战斗 = {AI=sx.智能}
	 }
	 for i=2,4 do
		  local sx = self:取属性(等级)
		  战斗单位[i]={
		  名称="巡逻小妖"
		  ,模型=模型范围[取随机数(1,#模型范围)]
		  ,等级=等级
		  ,饰品显示=true
		  ,气血 = qz((sx.属性.气血+等级*150)*难度)+等级*123.2
	 	  ,伤害 = qz(sx.属性.伤害*难度)+222.7
	 	  ,法伤 = qz(sx.属性.法防*难度)+111.9
		  ,速度 = qz(sx.属性.速度*难度)
		  ,固定伤害 = qz(等级*2*难度)
		  ,治疗能力 = qz(等级*2*难度)
		  ,防御 = 13.13+等级*6
		  ,法防 = 12.12+等级*0
	        --,修炼 = {物抗=修炼,法抗=修炼,攻修=修炼}
	        ,技能={"感知"}
	        ,主动技能=取随机功法组合(15)
		  }
	 end
	 战斗单位[5]={
		  名称="狐狸精"
		  ,模型="狐狸精"
		  ,变异=true
		  ,等级=等级
		  ,饰品显示=true
                          ,气血 = qz((sx.属性.气血+等级*150)*难度)+等级*123.2
	 	  ,伤害 = qz(sx.属性.伤害*难度)+222.7
	 	  ,法伤 = qz(sx.属性.法防*难度)+111.9
		  ,速度 = qz(sx.属性.速度*难度)
		  ,固定伤害 = qz(等级*2*难度)
		  ,治疗能力 = qz(等级*2*难度)
		  ,防御 = 13.13+等级*6
		  ,法防 = 12.12+等级*0
		  ,修炼 = {物抗=qz((等级-20)/12),法抗=qz((等级-20)/12),攻修=qz((等级-20)/12)}
		  ,主动技能={"失心符"}
	 }
	 for i=6,10 do
		  local sx = self:取属性(等级)
		  战斗单位[i]={
		  名称="巡逻小妖"
		  ,模型=模型范围[取随机数(1,#模型范围)]
		  ,等级=等级
		  ,饰品显示=true
		  ,气血 = qz((sx.属性.气血+等级*150)*难度)+等级*123.2
	 	  ,伤害 = qz(sx.属性.伤害*难度)+222.7
	 	  ,法伤 = qz(sx.属性.法防*难度)+111.9
		  ,速度 = qz(sx.属性.速度*难度)
		  ,固定伤害 = qz(等级*2*难度)
		  ,治疗能力 = qz(等级*2*难度)
		  ,防御 = 13.13+等级*6
		  ,法防 = 12.12+等级*0
        --,修炼 = {物抗=修炼,法抗=修炼,攻修=修炼}
        ,技能={"感知"}
        ,主动技能=取随机功法组合(15)
		  }
	 end
	 return 战斗单位
end

