function 怪物属性:属性表(lv,类型)
	 if 类型=="物理" then
		return {伤害 = lv*18 , 法伤= lv*3 , 防御= lv*10 , 法防= lv*3 , 速度= lv*2 ,气血=lv*8}
	 elseif 类型=="法系" then
		return {伤害 = lv*13 , 法伤= lv*6 , 防御= lv*10 , 法防= lv*5 , 速度= lv*1.2 ,气血=lv*8}
	 elseif 类型=="固伤" then --类型 女儿村
		return {伤害 = lv*13 , 法伤= lv*3 , 防御= lv*10 , 法防= lv*3 , 速度= lv*3 ,气血=lv*8}
	 elseif 类型=="封系" then
		return {伤害 = lv*13 , 法伤= lv*3 , 防御= lv*10 , 法防= lv*3 , 速度= lv*5 ,气血=lv*7}
	 elseif 类型=="辅助" then
		return {伤害 = lv*13 , 法伤= lv*3 , 防御= lv*15 , 法防= lv*4 , 速度= lv*2.1 ,气血=lv*9}
	 else --物法
		return {伤害 = lv*18 , 法伤= lv*6 , 防御= lv*10 , 法防= lv*3 , 速度= lv*2 ,气血=lv*8}

	 end
end
